mapper.select:
SELECT tmp.*, sml.open_price as openPoce, sml.pre_close_price as preClosePrice FROM( SELECT smi.trade_account as tradeAmt, smi.mark_Id as code, smi.mark_name as name, date_format(smi.cur_time,'%Y%m%d%H%i') as curDate, smi.trade_volume as tradeVol, smi.updown_rate as upDown, smi.current_price as tradePrice FROM stock_market_index_info AS smi WHERE smi.cur_time =#{timePoint} AND smi.mark_Id IN
#{marketId}
and smi.cur_time = #{timePoint} ) AS tmp LEFT JOIN stock_market_log_price AS sml ON tmp.code = sml.market_code AND DATE_FORMAT( sml.cur_date, '%Y%m%d' )= DATE_FORMAT(#{timePoint},'%Y%m%d' )

SELECT sum(smi.trade_volume) as count, DATE_FORMAT(smi.cur_time,'%Y%m%d%H%i') as time FROM stock_market_index_info AS smi WHERE smi.mark_id in
#{marketId}
AND cur_time BETWEEN #{startTime} AND #{endTime} GROUP BY smi.cur_time ORDER BY smi.cur_time asc
